const leads = $input.all().map(i => i.json);

// Flatten if nested array
const allLeads = Array.isArray(leads[0]) ? leads[0] : leads;

if (!allLeads || allLeads.length === 0 || allLeads[0]?.error) {
  return [{ json: { _empty: true, reason: 'No active leads found' } }];
}

const now = new Date();

function daysBetween(dateStr, ref) {
  if (!dateStr) return 9999;
  const d = new Date(dateStr);
  return Math.floor((ref - d) / (1000 * 60 * 60 * 24));
}

const results = [];

for (const lead of allLeads) {
  if (!lead.id || !lead.email) continue;

  const status = lead.status || 'new';
  const daysSinceCreated = daysBetween(lead.created_at, now);
  const daysSinceLastContact = daysBetween(lead.last_contacted_at, now);

  // GATING: Skip if already in terminal state
  if (['converted', 'unsubscribed', 'rejected', 'demo_booked', 'paying', 'churned', 'completed'].includes(status)) {
    continue;
  }

  // GATING: Skip if contacted too recently (min 2 days between touches)
  if (daysSinceLastContact < 2) {
    continue;
  }

  // Sequence timeline
  const touchCount = lead.touch_count || 0;
  const sequence = [
    { day: 0, channel: 'email', type: 'initial' },
    { day: 2, channel: 'call', type: 'follow_up_call_1' },
    { day: 4, channel: 'email', type: 'follow_up_1' },
    { day: 7, channel: 'call', type: 'follow_up_call_2' },
    { day: 10, channel: 'email', type: 'follow_up_2' },
    { day: 14, channel: 'call', type: 'final_call' },
    { day: 21, channel: 'email', type: 'breakup' }
  ];

  // If all touches exhausted, mark as completed
  if (touchCount >= sequence.length) {
    results.push({
      json: {
        ...lead,
        action: 'COMPLETE',
        type: 'sequence_exhausted',
        touchNumber: touchCount,
        reason: 'All 7 touches completed'
      }
    });
    continue;
  }

  const nextTouch = sequence[touchCount];
  if (daysSinceCreated < nextTouch.day) {
    continue; // Not time yet
  }

  results.push({
    json: {
      ...lead,
      action: nextTouch.channel.toUpperCase(),
      type: nextTouch.type,
      touchNumber: touchCount + 1,
      totalTouches: sequence.length
    }
  });
}

if (results.length === 0) {
  return [{ json: { _empty: true, reason: 'No leads due for a touch today' } }];
}

return results;

// ANTI-AI DETECTION RULES (MANDATORY FOR ALL CUSTOMER-FACING CONTENT):
// - NEVER use: delve, leverage, utilize, harness, elevate, empower, streamline, robust, seamless, cutting-edge, game-changer, innovative, revolutionize, best-in-class, holistic, synergy, paradigm
// - NEVER use em dashes (use regular dashes)
// - ALWAYS use contractions (I'm, can't, won't, you're, we're, it's, don't, isn't)
// - Vary sentence length (some 3 words, some 30)
// - Include casual imperfections (start with "And" or "But", sentence fragments OK)
// - Sound like a real person typing, not a marketing team
// - Keep paragraphs short (1-3 sentences)
// - Write at 8th grade reading level

// Pre-flight gating check + email build
// Looks up business details from Supabase using the lead's business_id
const lead = $input.first().json;

const SUPABASE_URL = 'https://wjukfdziomnejtlmegvv.supabase.co';
const SERVICE_KEY = $env.SUPABASE_SERVICE_KEY;
const leadBusinessId = lead.business_id || 'bayflow';

// --- Step 1: Re-check lead status (may have changed since fetch) ---
try {
  const response = await fetch(
    `${SUPABASE_URL}/rest/v1/cold_email_leads?id=eq.${lead.id}&select=status,sequence_stage`,
    {
      headers: {
        'apikey': SERVICE_KEY,
        'Authorization': `Bearer ${SERVICE_KEY}`
      }
    }
  );
  const current = await response.json();
  if (current && current[0]) {
    const currentStatus = current[0].status;
    if (['converted', 'unsubscribed', 'rejected', 'demo_booked', 'paying', 'churned'].includes(currentStatus)) {
      return [{ json: { ...lead, _gated: true, reason: 'Status changed to ' + currentStatus } }];
    }
  }
} catch (e) {
  // Continue if check fails - better to send than to skip
}

// --- Step 2: Look up business details from Supabase ---
let bizName = leadBusinessId;
let bizSiteUrl = '';
let bizCategory = '';
let bizTagline = '';
let bizSendingDomain = '';
let bizValueProp = '';

try {
  const bizResp = await fetch(
    `${SUPABASE_URL}/rest/v1/businesses?business_id=eq.${leadBusinessId}&select=name,site_url,category,tagline,sending_domain,value_prop`,
    {
      headers: {
        'apikey': SERVICE_KEY,
        'Authorization': `Bearer ${SERVICE_KEY}`
      }
    }
  );
  const bizRows = await bizResp.json();
  if (bizRows && bizRows[0]) {
    const biz = bizRows[0];
    bizName = biz.name || bizName;
    bizSiteUrl = biz.site_url || '';
    bizCategory = biz.category || '';
    bizTagline = biz.tagline || '';
    bizSendingDomain = biz.sending_domain || '';
    bizValueProp = biz.value_prop || '';
  }
} catch (e) {
  // Use defaults if lookup fails
}

// Derive sending email and vertical description from business data
const siteHost = bizSiteUrl ? new URL(bizSiteUrl).hostname : (bizSendingDomain || (leadBusinessId + '.app'));
const emailFrom = 'shalin@' + siteHost;
const emailFromName = 'Shalin from ' + bizName;

// Build a human-friendly vertical description from category
const verticalMap = {
  'auto_repair': 'independent auto repair shops',
  'dental': 'dental practices',
  'hvac': 'HVAC contractors',
  'plumbing': 'plumbing companies',
  'landscaping': 'landscaping businesses',
  'salon': 'salons and barbershops',
  'fitness': 'fitness studios and gyms',
  'restaurant': 'restaurants',
  'legal': 'small law firms',
  'accounting': 'accounting firms',
  'real_estate': 'real estate agencies',
  'cleaning': 'cleaning companies',
  'pet_care': 'pet care businesses'
};
const verticalDesc = verticalMap[bizCategory] || (bizCategory ? bizCategory.replace(/_/g, ' ') + ' businesses' : 'small businesses');

// Generic value prop: use DB field if available, otherwise a safe generic
const valueStatement = bizValueProp || bizTagline || ('streamlined operations, automated customer updates, and a modern online experience');

// Build email content based on touch type
const type = lead.type;
const firstName = lead.first_name || 'there';
const businessName = lead.business_name || 'your business';

let subject = '';
let body = '';

switch (type) {
  case 'initial':
    subject = `Quick question about ${businessName}`;
    body = `Hi ${firstName},\n\nI came across ${businessName} and thought you might dig what we're building. We made ${bizName} specifically for ${verticalDesc} - ${valueStatement}. Most shops save 5+ hours a week.\n\nWould you be up for a quick 10-minute demo this week?\n\nShalin\n${bizName}`;
    break;
  case 'follow_up_1':
    subject = `${firstName}, one more thought about ${businessName}`;
    body = `Hi ${firstName},\n\nJust following up on my last email. I know you're busy running things.\n\nOne thing our customers can't stop talking about: ${valueStatement}. No more manual busywork.\n\nI'd love to show you in 10 minutes if you're interested.\n\nShalin\n${bizName}`;
    break;
  case 'follow_up_2':
    subject = `Businesses like ${businessName} are going digital`;
    body = `Hi ${firstName},\n\nQuick note - we recently onboarded 3 businesses similar to ${businessName} and they've seen a 30% drop in admin time within the first month.\n\nI'd love to show you how it works. No commitment, just a quick walkthrough.\n\nWorth 10 minutes?\n\nShalin\n${bizName}`;
    break;
  case 'breakup':
    subject = `Last note from me, ${firstName}`;
    body = `Hi ${firstName},\n\nI've reached out a few times and don't want to be a pest. This is my last message.\n\nIf you ever want to check out a management system built for ${verticalDesc}, we're here: ${bizSiteUrl || ('https://' + siteHost)}\n\nWishing ${businessName} all the best.\n\nShalin\n${bizName}`;
    break;
  default:
    subject = `Quick question for ${businessName}`;
    body = `Hi ${firstName},\n\nWanted to reach out about ${bizName} - it's management software we built for ${verticalDesc}.\n\nWould you be up for a quick chat?\n\nShalin\n${bizName}`;
}

return [{
  json: {
    ...lead,
    _gated: false,
    emailSubject: subject,
    emailBody: body,
    emailTo: lead.email,
    emailFrom,
    emailFromName,
    _bizName: bizName,
    _bizSiteUrl: bizSiteUrl,
    _bizCategory: bizCategory,
    _bizVerticalDesc: verticalDesc,
    _leadBusinessId: leadBusinessId
  }
}];

// Ensure a Smartlead campaign exists for this business.
// Checks Supabase for an existing campaign_id; if none, creates one via Smartlead API.
// Stores the campaign_id back in Supabase for reuse on subsequent runs.

const lead = $input.first().json;
const SMARTLEAD_API_KEY = $env.SMARTLEAD_API_KEY;
const SUPABASE_URL = 'https://wjukfdziomnejtlmegvv.supabase.co';
const SERVICE_KEY = $env.SUPABASE_SERVICE_KEY;
const BUSINESS_ID = lead._leadBusinessId || lead.business_id || 'bayflow';
const BIZ_NAME = lead._bizName || BUSINESS_ID;

let campaignId = null;

// Step 1: Check Supabase for existing Smartlead campaign_id
try {
  const resp = await fetch(
    `${SUPABASE_URL}/rest/v1/smartlead_campaigns?business_id=eq.${BUSINESS_ID}&select=campaign_id&limit=1`,
    {
      headers: {
        'apikey': SERVICE_KEY,
        'Authorization': `Bearer ${SERVICE_KEY}`
      }
    }
  );
  const rows = await resp.json();
  if (rows && rows.length > 0 && rows[0].campaign_id) {
    campaignId = rows[0].campaign_id;
  }
} catch (e) {
  // Will attempt to create below
}

// Step 2: If no campaign exists, create one via Smartlead API
if (!campaignId) {
  try {
    const campaignName = `${BIZ_NAME} Cold Outreach - ${$now.toFormat('yyyy-MM-dd')}`;
    const createResp = await fetch(
      `https://server.smartlead.ai/api/v1/campaigns/create?api_key=${SMARTLEAD_API_KEY}`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name: campaignName
        })
      }
    );
    const createData = await createResp.json();
    campaignId = createData.id || createData.campaign_id || null;

    if (campaignId) {
      // Store campaign_id in Supabase for reuse
      try {
        await fetch(
          `${SUPABASE_URL}/rest/v1/smartlead_campaigns`,
          {
            method: 'POST',
            headers: {
              'apikey': SERVICE_KEY,
              'Authorization': `Bearer ${SERVICE_KEY}`,
              'Content-Type': 'application/json',
              'Prefer': 'return=minimal'
            },
            body: JSON.stringify({
              business_id: BUSINESS_ID,
              campaign_id: String(campaignId),
              campaign_name: campaignName,
              created_at: new Date().toISOString()
            })
          }
        );
      } catch (e) {
        // Non-fatal: campaign was created in Smartlead even if Supabase save fails
      }

      // Step 3: Set sending schedule on the new campaign
      try {
        await fetch(
          `https://server.smartlead.ai/api/v1/campaigns/${campaignId}/schedule?api_key=${SMARTLEAD_API_KEY}`,
          {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              timezone: 'America/New_York',
              days_of_the_week: [1, 2, 3, 4],
              start_hour: '08:00',
              end_hour: '17:00',
              min_time_btw_emails: 8,
              max_new_leads_per_day: 30
            })
          }
        );
      } catch (e) {
        // Non-fatal: schedule can be set manually in Smartlead dashboard
      }
    }
  } catch (e) {
    // Campaign creation failed -- will pass campaignId=null downstream
  }
}

return [{
  json: {
    ...lead,
    smartlead_campaign_id: campaignId
  }
}];

// Pre-flight gating check for call with TCPA compliance
const lead = $input.first().json;

const SUPABASE_URL = 'https://wjukfdziomnejtlmegvv.supabase.co';
const SERVICE_KEY = $env.SUPABASE_SERVICE_KEY;

// --- Step 1: Re-check lead status (may have changed since fetch) ---
try {
  const response = await fetch(
    `${SUPABASE_URL}/rest/v1/cold_email_leads?id=eq.${lead.id}&select=status,sequence_stage,dnc_checked,phone,timezone`,
    {
      headers: {
        'apikey': SERVICE_KEY,
        'Authorization': `Bearer ${SERVICE_KEY}`
      }
    }
  );
  const current = await response.json();
  if (current && current[0]) {
    const currentStatus = current[0].status;
    if (['converted', 'unsubscribed', 'rejected', 'demo_booked', 'paying', 'churned'].includes(currentStatus)) {
      return [{ json: { ...lead, _gated: true, _fallback_to_email: false, reason: 'Status changed to ' + currentStatus } }];
    }
    // TCPA: Check DNC flag
    if (current[0].dnc_checked === true) {
      return [{ json: { ...lead, _gated: true, _fallback_to_email: false, reason: 'TCPA: Lead is on DNC list' } }];
    }
  }
} catch (e) {
  // Continue if check fails - better to gate than to skip
}

// --- Step 2: Check phone number exists - fall back to email if missing ---
if (!lead.phone) {
  return [{ json: { ...lead, _gated: true, _fallback_to_email: true, reason: 'No phone number - falling back to email' } }];
}

// --- Step 3: TCPA business hours check (8 AM - 9 PM in lead's timezone) ---
const leadTimezone = lead.timezone || 'America/New_York';
try {
  const nowInLeadTz = new Date(new Date().toLocaleString('en-US', { timeZone: leadTimezone }));
  const hour = nowInLeadTz.getHours();
  if (hour < 8 || hour >= 21) {
    return [{ json: { ...lead, _gated: true, _fallback_to_email: true, reason: `TCPA: Outside business hours (${hour}:00 in ${leadTimezone}). Allowed: 8AM-9PM.` } }];
  }
} catch (e) {
  // If timezone parsing fails, use UTC check as fallback
  const utcHour = new Date().getUTCHours();
  // Assume US Eastern (UTC-5) as safe default
  const estHour = (utcHour - 5 + 24) % 24;
  if (estHour < 8 || estHour >= 21) {
    return [{ json: { ...lead, _gated: true, _fallback_to_email: true, reason: `TCPA: Outside business hours (EST fallback: ${estHour}:00)` } }];
  }
}

// --- Step 4: TCPA - check lead hasn't said "don't call" ---
const status = lead.status || '';
if (['rejected', 'unsubscribed'].includes(status)) {
  return [{ json: { ...lead, _gated: true, _fallback_to_email: false, reason: 'TCPA: Lead status is ' + status } }];
}

return [{ json: { ...lead, _gated: false, _fallback_to_email: false } }];

// Update lead after EMAIL action (via Smartlead)
const lead = $('Gate Check + Build Email').first().json;
const smartleadResult = $input.first().json;
const now = $now.toFormat('yyyy-MM-dd\'T\'HH:mm:ss.SSS\'Z\'');
const touchNumber = lead.touchNumber || 1;
const leadBusinessId = lead._leadBusinessId || lead.business_id || 'bayflow';
const bizCategory = lead._bizCategory || '';

const SUPABASE_URL = 'https://wjukfdziomnejtlmegvv.supabase.co';
const SERVICE_KEY = $env.SUPABASE_SERVICE_KEY;

// Determine new status based on touch type
let newStatus = lead.status;
if (lead.type === 'initial') newStatus = 'contacted';
else if (lead.type === 'follow_up_1') newStatus = 'follow_up_1';
else if (lead.type === 'follow_up_2') newStatus = 'follow_up_2';
else if (lead.type === 'breakup') newStatus = 'completed';

// Extract Smartlead upload status
const smartleadOk = !!(smartleadResult && !smartleadResult.error);
const smartleadCampaignId = lead.smartlead_campaign_id || $('Ensure Smartlead Campaign').first().json.smartlead_campaign_id || null;

// Update lead record
try {
  await fetch(
    `${SUPABASE_URL}/rest/v1/cold_email_leads?id=eq.${lead.id}`,
    {
      method: 'PATCH',
      headers: {
        'apikey': SERVICE_KEY,
        'Authorization': `Bearer ${SERVICE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify({
        touch_count: touchNumber,
        last_contacted_at: now,
        last_touch_channel: 'email',
        sequence_stage: lead.type === 'breakup' ? 'completed' : 'contacted',
        status: newStatus,
        last_email_type: lead.type,
        smartlead_campaign_id: smartleadCampaignId ? String(smartleadCampaignId) : null,
        updated_at: now
      })
    }
  );
} catch (e) {
  // Log but don't fail
}

// Log to activities
try {
  await fetch(
    `${SUPABASE_URL}/rest/v1/activities`,
    {
      method: 'POST',
      headers: {
        'apikey': SERVICE_KEY,
        'Authorization': `Bearer ${SERVICE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify({
        lead_id: lead.id,
        business_id: leadBusinessId,
        activity_type: 'email_queued_smartlead',
        channel: 'email',
        details: {
          touch_number: touchNumber,
          email_type: lead.type,
          subject: lead.emailSubject,
          smartlead_campaign_id: smartleadCampaignId,
          smartlead_upload_ok: smartleadOk
        }
      })
    }
  );
} catch (e) {}

// Log to outreach_intelligence
try {
  const dayOfWeek = new Date().getDay();
  const hourOfDay = new Date().getHours();
  await fetch(
    `${SUPABASE_URL}/rest/v1/outreach_intelligence`,
    {
      method: 'POST',
      headers: {
        'apikey': SERVICE_KEY,
        'Authorization': `Bearer ${SERVICE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify({
        business_id: leadBusinessId,
        channel: 'email',
        outreach_type: lead.type,
        audience_type: bizCategory || 'general',
        tone: 'friendly',
        angle: lead.type === 'follow_up_2' ? 'social_proof' : 'pain_point',
        intent: 'book_demo',
        subject_line: lead.emailSubject,
        content_preview: (lead.emailBody || '').substring(0, 200),
        content_full: lead.emailBody,
        personalization_depth: 2,
        day_of_week: dayOfWeek,
        hour_of_day: hourOfDay,
        lead_id: lead.id,
        lead_email: lead.email,
        sending_provider: 'smartlead',
        smartlead_campaign_id: smartleadCampaignId
      })
    }
  );
} catch (e) {}

return [{
  json: {
    action: 'EMAIL_QUEUED_SMARTLEAD',
    leadId: lead.id,
    email: lead.email,
    type: lead.type,
    touchNumber: touchNumber,
    smartleadCampaignId: smartleadCampaignId,
    smartleadUploadOk: smartleadOk,
    businessId: leadBusinessId
  }
}];

// Update lead after CALL action
const lead = $('Gate Check for Call').first().json;
const callResult = $input.first().json;
const now = $now.toFormat('yyyy-MM-dd\'T\'HH:mm:ss.SSS\'Z\'');
const touchNumber = lead.touchNumber || 1;
const leadBusinessId = lead.business_id || 'bayflow';
const bizCategory = lead._bizCategory || lead.category || '';

const SUPABASE_URL = 'https://wjukfdziomnejtlmegvv.supabase.co';
const SERVICE_KEY = $env.SUPABASE_SERVICE_KEY;

// Update lead record
try {
  await fetch(
    `${SUPABASE_URL}/rest/v1/cold_email_leads?id=eq.${lead.id}`,
    {
      method: 'PATCH',
      headers: {
        'apikey': SERVICE_KEY,
        'Authorization': `Bearer ${SERVICE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify({
        touch_count: touchNumber,
        last_contacted_at: now,
        last_touch_channel: 'call',
        sequence_stage: 'contacted',
        call_attempts: (lead.call_attempts || 0) + 1,
        call_status: 'attempted',
        updated_at: now
      })
    }
  );
} catch (e) {}

// Log to activities
try {
  await fetch(
    `${SUPABASE_URL}/rest/v1/activities`,
    {
      method: 'POST',
      headers: {
        'apikey': SERVICE_KEY,
        'Authorization': `Bearer ${SERVICE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify({
        lead_id: lead.id,
        business_id: leadBusinessId,
        activity_type: 'call_made',
        channel: 'phone',
        details: {
          touch_number: touchNumber,
          call_type: lead.type,
          call_result_id: callResult?.callId || null
        }
      })
    }
  );
} catch (e) {}

// Log to outreach_intelligence
try {
  const dayOfWeek = new Date().getDay();
  const hourOfDay = new Date().getHours();
  await fetch(
    `${SUPABASE_URL}/rest/v1/outreach_intelligence`,
    {
      method: 'POST',
      headers: {
        'apikey': SERVICE_KEY,
        'Authorization': `Bearer ${SERVICE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify({
        business_id: leadBusinessId,
        channel: 'call',
        outreach_type: lead.type,
        audience_type: bizCategory || 'general',
        tone: 'friendly',
        intent: 'book_demo',
        day_of_week: dayOfWeek,
        hour_of_day: hourOfDay,
        lead_id: lead.id,
        lead_email: lead.email
      })
    }
  );
} catch (e) {}

return [{
  json: {
    action: 'CALL_TRIGGERED',
    leadId: lead.id,
    phone: lead.phone,
    type: lead.type,
    touchNumber: touchNumber,
    businessId: leadBusinessId
  }
}];

// Mark sequence-exhausted leads as completed
const lead = $input.first().json;
const now = $now.toFormat('yyyy-MM-dd\'T\'HH:mm:ss.SSS\'Z\'');

const SUPABASE_URL = 'https://wjukfdziomnejtlmegvv.supabase.co';
const SERVICE_KEY = $env.SUPABASE_SERVICE_KEY;

try {
  await fetch(
    `${SUPABASE_URL}/rest/v1/cold_email_leads?id=eq.${lead.id}`,
    {
      method: 'PATCH',
      headers: {
        'apikey': SERVICE_KEY,
        'Authorization': `Bearer ${SERVICE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify({
        status: 'completed',
        sequence_stage: 'completed',
        updated_at: now
      })
    }
  );
} catch (e) {}

return [{ json: { action: 'COMPLETED', leadId: lead.id, email: lead.email, businessId: lead.business_id || 'unknown' } }];

// Aggregate all actions taken for summary
const emailActions = [];
const callActions = [];
const completeActions = [];

try {
  const emailItems = $('Update Lead After Email').all();
  emailItems.forEach(i => emailActions.push(i.json));
} catch (e) {}

try {
  const callItems = $('Update Lead After Call').all();
  callItems.forEach(i => callActions.push(i.json));
} catch (e) {}

try {
  const completeItems = $('Mark Sequence Complete').all();
  completeItems.forEach(i => completeActions.push(i.json));
} catch (e) {}

const totalActions = emailActions.length + callActions.length + completeActions.length;

// Collect unique business IDs across all actions
const allActions = [...emailActions, ...callActions, ...completeActions];
const bizIds = [...new Set(allActions.map(a => a.businessId).filter(Boolean))];
const bizSummary = bizIds.length > 0 ? ' (businesses: ' + bizIds.join(', ') + ')' : '';

const summary = `Sales Sequence Summary (via Smartlead)${bizSummary}:\n- Emails queued to Smartlead: ${emailActions.length}\n- Calls triggered: ${callActions.length}\n- Sequences completed: ${completeActions.length}\n- Total actions: ${totalActions}`;

return [{
  json: {
    summary,
    emailsQueued: emailActions.length,
    callsTriggered: callActions.length,
    sequencesCompleted: completeActions.length,
    totalActions,
    businessIds: bizIds
  }
}];

// Parse Smartlead reply webhook payload
// Smartlead webhook sends: { event_type, lead_email, campaign_id, reply_text, reply_subject, ... }
const payload = $input.first().json.body || $input.first().json;

const fromEmail = payload.lead_email || payload.to_email || payload.email || '';
const subject = payload.reply_subject || payload.subject || '';
const body = payload.reply_text || payload.reply_body || payload.text || '';
const campaignId = payload.campaign_id || null;
const replyDate = new Date().toISOString();

// Unsubscribe detection (CAN-SPAM compliance)
const unsubscribeKeywords = ['unsubscribe', 'remove me', 'stop emailing', 'opt out', 'opt-out', 'take me off', 'remove my email'];
const bodyLower = body.toLowerCase();
const subjectLower = subject.toLowerCase();
const isUnsubscribe = unsubscribeKeywords.some(kw => bodyLower.includes(kw) || subjectLower.includes(kw));

if (isUnsubscribe) {
  return [{
    json: {
      fromEmail: fromEmail.replace(/<|>/g, '').trim(),
      subject,
      body: body.substring(0, 2000),
      sentiment: 'unsubscribe',
      isUnsubscribe: true,
      smartleadCampaignId: campaignId,
      replyDate
    }
  }];
}

// Standard sentiment detection for non-unsubscribe replies
const positiveKeywords = ['interested', 'yes', 'sure', 'tell me more', 'demo', 'try', 'sign up', 'pricing', 'sounds good', 'let\'s talk', 'schedule', 'call me'];
const negativeKeywords = ['not interested', 'no thanks', 'no thank', 'pass', 'not for us'];

let sentiment = 'neutral';

if (positiveKeywords.some(kw => bodyLower.includes(kw))) {
  sentiment = 'positive';
} else if (negativeKeywords.some(kw => bodyLower.includes(kw))) {
  sentiment = 'negative';
}

return [{
  json: {
    fromEmail: fromEmail.replace(/<|>/g, '').trim(),
    subject,
    body: body.substring(0, 2000),
    sentiment,
    isUnsubscribe: false,
    smartleadCampaignId: campaignId,
    replyDate
  }
}];

// Mark lead as unsubscribed in Supabase
const reply = $('Parse Smartlead Reply').first().json;
const SUPABASE_URL = 'https://wjukfdziomnejtlmegvv.supabase.co';
const SERVICE_KEY = $env.SUPABASE_SERVICE_KEY;

try {
  await fetch(
    `${SUPABASE_URL}/rest/v1/cold_email_leads?email=eq.${encodeURIComponent(reply.fromEmail)}`,
    {
      method: 'PATCH',
      headers: {
        'apikey': SERVICE_KEY,
        'Authorization': `Bearer ${SERVICE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify({
        status: 'unsubscribed',
        unsubscribed_at: reply.replyDate
      })
    }
  );
} catch (e) {}

return [{ json: { action: 'UNSUBSCRIBED', email: reply.fromEmail } }];

// Update lead as replied + log to outreach intelligence + notify
const reply = $('Parse Smartlead Reply').first().json;
const SUPABASE_URL = 'https://wjukfdziomnejtlmegvv.supabase.co';
const SERVICE_KEY = $env.SUPABASE_SERVICE_KEY;

// Update lead status to replied
try {
  await fetch(
    `${SUPABASE_URL}/rest/v1/cold_email_leads?email=eq.${encodeURIComponent(reply.fromEmail)}`,
    {
      method: 'PATCH',
      headers: {
        'apikey': SERVICE_KEY,
        'Authorization': `Bearer ${SERVICE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify({
        status: 'replied',
        replied_at: reply.replyDate,
        reply_sentiment: reply.sentiment
      })
    }
  );
} catch (e) {}

// Determine outcome for outreach intelligence
let outcome = 'replied_neutral';
if (reply.sentiment === 'positive') outcome = 'replied_positive';
else if (reply.sentiment === 'negative') outcome = 'replied_negative';

// Update outreach_intelligence with outcome
try {
  await fetch(
    `${SUPABASE_URL}/rest/v1/outreach_intelligence?lead_email=eq.${encodeURIComponent(reply.fromEmail)}&outcome=eq.pending&order=created_at.desc&limit=1`,
    {
      method: 'PATCH',
      headers: {
        'apikey': SERVICE_KEY,
        'Authorization': `Bearer ${SERVICE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify({
        outcome: outcome,
        outcome_at: reply.replyDate,
        notes: reply.body.substring(0, 300),
        what_worked: reply.sentiment === 'positive' ? 'Lead responded positively via Smartlead. Preview: ' + reply.body.substring(0, 100) : null
      })
    }
  );
} catch (e) {}

return [{
  json: {
    action: 'REPLY_PROCESSED',
    email: reply.fromEmail,
    sentiment: reply.sentiment,
    smartleadCampaignId: reply.smartleadCampaignId
  }
}];

